        this.type = args.type;
        this.publicMessage = args.publicMessage;
        this.id = args.id;
      }
    }
    return {build: () => createValidate<RpcError<'test-error'>>(), buildErrors: () => noErrs(createGetValidationErrors<RpcError<'test-error'>>())};
  })()

